import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI, Type } from "@google/genai";
import dns from "dns";

// Enable DNS resolution caching or fallback
dns.setDefaultResultOrder("ipv4first");

const app = express();
const PORT = 3000;

app.use(express.json());

// Initialize Gemini SDK with telemetry header as required by rules
const ai = new GoogleGenAI({
  apiKey: process.env.GEMINI_API_KEY,
  httpOptions: {
    headers: {
      "User-Agent": "aistudio-build",
    },
  },
});

// Endpoint to fetch GitHub repositories for any username
app.get("/api/github/repos", async (req, res) => {
  const { username, token } = req.query;

  if (!username || typeof username !== "string") {
    res.status(400).json({ error: "O nome de usuário do GitHub é obrigatório." });
    return;
  }

  try {
    const headers: Record<string, string> = {
      Accept: "application/vnd.github.v3+json",
      "User-Agent": "GitHub-Sites-Hub-AI-Studio",
    };

    if (token && typeof token === "string" && token.trim() !== "") {
      headers["Authorization"] = `Bearer ${token}`;
    }

    // Fetch up to 100 repositories, sorted by updated
    const githubUrl = `https://api.github.com/users/${encodeURIComponent(username)}/repos?per_page=100&sort=updated`;
    const response = await fetch(githubUrl, { headers });

    if (!response.ok) {
      if (response.status === 404) {
        res.status(404).json({ error: `Usuário do GitHub "${username}" não encontrado.` });
        return;
      }
      if (response.status === 403) {
        res.status(403).json({
          error: "Limite de requisições do GitHub atingido para este IP. Insira um Token de Acesso Pessoal (PAT) nas configurações para continuar ou tente mais tarde.",
        });
        return;
      }
      throw new Error(`GitHub API returned state: ${response.status} ${response.statusText}`);
    }

    const repos = await response.json();
    res.json(repos);
  } catch (error: any) {
    console.error("Erro ao buscar repositórios do GitHub:", error);
    res.status(500).json({ error: error.message || "Falha ao conectar com a API do GitHub." });
  }
});

// Endpoint to fetch raw readme for analysis
app.get("/api/github/readme", async (req, res) => {
  const { owner, repo, defaultBranch } = req.query;

  if (!owner || !repo) {
    res.status(400).json({ error: "Parâmetros 'owner' e 'repo' são obrigatórios." });
    return;
  }

  const branch = (defaultBranch as string) || "main";
  const readmeUrls = [
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/${branch}/README.md`,
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/${branch}/readme.md`,
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/master/README.md`,
    `https://raw.githubusercontent.com/${owner}/${repo}/refs/heads/master/readme.md`,
  ];

  for (const url of readmeUrls) {
    try {
      const resp = await fetch(url);
      if (resp.ok) {
        const text = await resp.text();
        res.json({ readme: text.substring(0, 4000) }); // Limit size to avoid overwhelming context
        return;
      }
    } catch (e) {
      // Continue to next fallback URL
    }
  }

  res.json({ readme: "" });
});

// Endpoint to analyze repository and deployment using Gemini API
app.post("/api/github/analyze", async (req, res) => {
  const { repoName, description, homepage, topics, readme, language } = req.body;

  if (!repoName) {
    res.status(400).json({ error: "O nome do repositório é obrigatório para análise." });
    return;
  }

  try {
    if (!process.env.GEMINI_API_KEY) {
      res.status(500).json({
        error: "Chave de API do Gemini não configurada no servidor. Cadastre-a nas configurações.",
      });
      return;
    }

    const prompt = `Analise as informações do seguinte repositório do GitHub e seu respectivo site anunciado para criar metadados ricos em Português (Brasil) para exibição em um painel central de portfólio.

Repositório: ${repoName}
Descrição fornecida no GitHub: ${description || "Sem descrição"}
URL do Site Deployed: ${homepage || "Sem homepage listada"}
Tópicos/Tags: ${Array.isArray(topics) ? topics.join(", ") : "Nenhum"}
Linguagem Principal: ${language || "Não especificada"}

Conteúdo resumido do README.md do projeto:
${readme || "Nenhum README disponível."}

Instruções:
1. Com base no nome, descrição, tags e README, determine DO QUE SE TRATA o projeto. Crie uma descrição elegante, atrativa e profissional em Português, ideal para um card de portfólio de alta categoria. (Máximo de 3 frases curtas e impactantes).
2. Categorize-o em uma das seguintes categorias padrão ou similar relevante: Portfólio, Landing Page, E-commerce, Dashboard/Painel, Jogo, Utilitário/Ferramenta, Blog, Aplicativo Web, Landing Page Produto, API/Backend.
3. Extraia o stack de tecnologias usadas relevantes (ex: React, Tailwind CSS, TypeScript, Vite, Node.js, CSS3, etc.).
4. Identifique até 3 recursos/destaques principais do projeto (funcionalidades inovadoras ou diferenciais).
5. Sugira até 2 dicas inteligentes de melhoria ou próximo passo para o projeto.
6. Forneça uma nota de portfólio criativa de 50 a 100 baseado na completeza do projeto (quantidade de informações, readme estruturado, etc).`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: prompt,
      config: {
        systemInstruction: "Você é um especialista em desenvolvimento web, avaliação de UI/UX e escrita técnica. Seu trabalho é analisar repositórios e gerar respostas estruturadas extremamente profissionais e em português.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          required: ["description", "category", "techStack", "highlights", "tips", "portfolioScore"],
          properties: {
            description: {
              type: Type.STRING,
              description: "Nova descrição polida de alta qualidade em português (Brasil) para o card do portfólio.",
            },
            category: {
              type: Type.STRING,
              description: "Categoria ideal do site (ex: Portfólio, E-commerce, Landing Page, Jogo, Utilitário, etc.)",
            },
            techStack: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Lista de tecnologias proeminentes detectadas.",
            },
            highlights: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Até 3 pontos fortes/funcionalidades de destaque do projeto.",
            },
            tips: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Até 2 sugestões inteligentes de melhoria.",
            },
            portfolioScore: {
              type: Type.INTEGER,
              description: "Uma pontuação de 50 a 100 para o projeto com base no nível de documentação e escopo.",
            },
          },
        },
      },
    });

    const parsedData = JSON.parse(response.text?.trim() || "{}");
    res.json(parsedData);
  } catch (error: any) {
    console.error("Erro na análise do Gemini:", error);
    res.status(500).json({ error: error.message || "Falha na análise de IA com o Gemini." });
  }
});

// Endpoint to validate a user-inserted Gemini API key
app.post("/api/gemini/validate", async (req, res) => {
  const { key } = req.body;
  if (!key || typeof key !== "string" || key.trim() === "") {
    res.status(400).json({ success: false, error: "Chave não informada." });
    return;
  }

  try {
    const tempAi = new GoogleGenAI({
      apiKey: key,
      httpOptions: {
        headers: {
          "User-Agent": "aistudio-build",
        },
      },
    });

    const response = await tempAi.models.generateContent({
      model: "gemini-3.5-flash",
      contents: "Diga apenas a palavra 'OK' em maiúsculo.",
    });

    if (response.text && response.text.trim().includes("OK")) {
      res.json({ success: true });
    } else {
      res.json({ success: true, warning: "Chave válida, mas formato de resposta inesperado." });
    }
  } catch (err: any) {
    console.error("Erro ao validar chave Gemini:", err);
    res.status(400).json({ success: false, error: err.message || "Chave inválida ou erro na validação." });
  }
});

// Endpoint to customize theme and template using Gemini Multimodal API
app.post("/api/theme/customize", async (req, res) => {
  const { prompt, image, mimeType, userKey, scope = "layout" } = req.body;

  // Use the manually entered user API key, or default to the server's GEMINI_API_KEY
  const activeApiKey = (userKey && typeof userKey === "string" && userKey.trim() !== "") 
    ? userKey 
    : process.env.GEMINI_API_KEY;

  if (!activeApiKey) {
    res.status(400).json({
      error: "Para personalizar o tema usando IA, é necessário configurar a Chave de API do Gemini no painel de expansão."
    });
    return;
  }

  try {
    const tempAi = new GoogleGenAI({
      apiKey: activeApiKey,
      httpOptions: {
        headers: {
          "User-Agent": "aistudio-build",
        },
      },
    });

    let scopeInstruction = "";
    if (scope === "colors") {
      scopeInstruction = "MODO DE ESCOPO: [SUBSTITUIR APENAS CORES]. Mude estritamente as propriedades de cor (bg, card, border, accent, text, gray, glowHex, gridOverlay) gerando paletas lindas e coerentes com contraste WCAG AA. O campo 'extraCSS' DEVE ser vazio ou conter apenas variáveis, preservando todo o layout, fontes originais, margens e padding intocados.";
    } else if (scope === "refine") {
      scopeInstruction = "MODO DE ESCOPO: [APENAS REFINAR LAYOUT]. Faça pequenos refinamentos cosméticos no tema, tipografias e pequenos extras de CSS (bordas, sutis sombras ou transições) baseados no prompt sem causar mudanças bruscas de estruturação física do app.";
    } else {
      scopeInstruction = "MODO DE ESCOPO: [TODO O LAYOUT]. Você está plenamente autorizado e incentivado a revolucionar a aparência e layout de qualquer componente de forma radical, usando o campo 'extraCSS' para estilizar livremente seletores chaves do app. Garanta que a essência e as funcionalidades (inputs, listas, links de click e botões) funcionem com perfeição!";
    }

    const runPrompt = `Você é um Designer Web Expert e engenheiro de interfaces ricas. O usuário quer redefinir totalmente a cara do seu app HUB de projetos.

${scopeInstruction}

${prompt ? `Solicitação do usuário: "${prompt}"` : "Crie um estilo inovador baseado na referência de imagem anexada."}

DIRETRIZES DE MANIPULAÇÃO DE COMPONENTES:
O aplicativo HTML e CSS no frontend expõe os seguintes IDs e classes para estilização via 'extraCSS' (apenas quando o escopo permitir modificações de layout):
- '#cyber-app-root': O contêiner pai de toda a tela viewport.
- '#cyber-sidebar': O menu de barra lateral (desktop) / cabeçalho superior (celular). Você pode mudar seu background, largura, bordas, sombras ou transformações.
- '#cyber-sidebar-logo-group': Logotipo e título reduzido na barra lateral.
- '#cyber-sidebar-metrics': Cartões e métricas de monitoramento numérico.
- '#cyber-sidebar-active-index': Status de indexador e botão de acesso ao GitHub.
- '#cyber-content-area': O painel principal à direita que rola e renderiza os aplicativos.
- '#cyber-filters-header': Painel de filtro de categorias, barra de busca e título.
- '#cyber-search-controls': Linha com os campos de input, selects e filtros.
- '#cyber-projects-grid': O grid CSS que alinha os cartões.
- '.repo-card': Os cartões de repositórios individuais. Pode customizar seu padding, border-radius, background, hover triggers, etc.
- '#btn-open-ai-customizer': O botão flutuante de IA do design menu.
- '#btn-github-access': O botão de credencial GitHub.

Crie um estilo impecável em Português. As cores devem garantir excelente legibilidade. O visual pode ser qualquer coisa que combine com a solicitação: vintage, ficção científica cyberpunk neon, minimalista nórdico, editorial preto e branco de alta costura, brutalista urbano moderno ou futurista cintilante. Retorne apenas o JSON no formato requisitado pelo esquema de estilo.`;

    const contentsParts: any[] = [];

    // Se houver uma imagem base64
    if (image && typeof image === "string" && image.trim() !== "") {
      const cleanBase64 = image.replace(/^data:image\/\w+;base64,/, "");
      contentsParts.push({
        inlineData: {
          data: cleanBase64,
          mimeType: mimeType || "image/png",
        }
      });
    }

    contentsParts.push({
      text: runPrompt,
    });

    const response = await tempAi.models.generateContent({
      model: "gemini-3.5-flash",
      contents: { parts: contentsParts },
      config: {
        systemInstruction: "Você é um gerador determinista altamente criativo de temas e estilos de aplicação de backend que retorna dados JSON compatíveis com o esquema de estilo.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          required: ["name", "description", "sidebarTitle", "theme"],
          properties: {
            name: {
              type: Type.STRING,
              description: "Nome customizado para o APP HUB (ex: Lyra Studio - App Hub, ou algo inspirado pelo prompt/estilo)."
            },
            description: {
              type: Type.STRING,
              description: "Subtítulo do HUB sintonizado com o estilo visual definido."
            },
            sidebarTitle: {
              type: Type.STRING,
              description: "Título reduzido da marca na barra lateral superior (ex: LYRA STUDIO ou sigla)."
            },
            theme: {
              type: Type.OBJECT,
              required: ["bg", "card", "border", "accent", "text", "gray", "gridOverlay", "glowHex", "fontSans", "fontDisplay", "extraCSS"],
              properties: {
                bg: { type: Type.STRING, description: "Cor hex do fundo principal" },
                card: { type: Type.STRING, description: "Cor hex de fundo dos componentes/cards" },
                border: { type: Type.STRING, description: "Cor hex de bordas e divisores" },
                accent: { type: Type.STRING, description: "Cor hex principal de destaques vibrantes" },
                text: { type: Type.STRING, description: "Cor hex do texto principal" },
                gray: { type: Type.STRING, description: "Cor hex do texto secundário" },
                gridOverlay: { type: Type.STRING, description: "Fórmula de background CSS para o fundo do viewport (ex: gradientes, patterns ou grids)." },
                glowHex: { type: Type.STRING, description: "Sombra de relevo ou cor brilhante (ex: rgba(x, y, z, 0.25) ou hex)." },
                fontSans: { type: Type.STRING, description: "Font-family sans-serif padrão para o corpo do texto" },
                fontDisplay: { type: Type.STRING, description: "Font-family para os headers e logos" },
                extraCSS: { type: Type.STRING, description: "Trecho de código CSS adicional se precisar para injetar no container." }
              }
            }
          }
        },
      }
    });

    const parsedTheme = JSON.parse(response.text?.trim() || "{}");
    res.json(parsedTheme);
  } catch (error: any) {
    console.error("Erro na personalização com Gemini:", error);
    res.status(500).json({ error: error.message || "Erro para personalizar com a Inteligência Artificial." });
  }
});

// Configure Vite middleware or static serving
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    // Mount Vite development server as middleware
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    // Serve static files in production
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`[Server] rodando com sucesso no endereço http://localhost:${PORT}`);
  });
}

startServer();
